### Variable Height Virtual Scrolling

```javascript
// web/src/components/VariableHeightVirtualList.js
export class VariableHeightVirtualList {
    constructor({
        container,
        totalCount,
        estimatedItemHeight,
        renderItem,
        measureItem
    }) {
        this.container = container;
        this.totalCount = totalCount;
        this.estimatedHeight = estimatedItemHeight;
        this.renderItem = renderItem;
        this.measureItem = measureItem;

        // Cache measured heights
        this.heights = new Map();
        this.positions = []; // Cumulative positions

        this.init();
    }

    getTotalHeight() {
        let total = 0;
        for (let i = 0; i < this.totalCount; i++) {
            total += this.heights.get(i) ?? this.estimatedHeight;
        }
        return total;
    }

    getItemPosition(index) {
        let pos = 0;
        for (let i = 0; i < index; i++) {
            pos += this.heights.get(i) ?? this.estimatedHeight;
        }
        return pos;
    }

    findIndexAtPosition(scrollTop) {
        let pos = 0;
        for (let i = 0; i < this.totalCount; i++) {
            const height = this.heights.get(i) ?? this.estimatedHeight;
            if (pos + height > scrollTop) {
                return i;
            }
            pos += height;
        }
        return this.totalCount - 1;
    }

    measureRenderedItems() {
        for (const [index, element] of this.items) {
            const height = this.measureItem(element);
            if (this.heights.get(index) !== height) {
                this.heights.set(index, height);
                console.debug(`[VirtualList] Measured item ${index}: ${height}px`);
            }
        }
    }
}
